1	------------------------------------------------------------------------------
2	--  Copyright (c) 2019 by Paul Scherrer Institute, Switzerland
3	--  All rights reserved.
4	--  Authors: Oliver Bruendler
5	------------------------------------------------------------------------------
6	
7	------------------------------------------------------------------------------
8	-- Libraries
9	------------------------------------------------------------------------------
10	
11	library ieee;
12	    use ieee.std_logic_1164.all;
13	    use ieee.numeric_std.all;
14	
15	library work;
16	    use work.psi_common_math_pkg.all;
17	    use work.psi_common_array_pkg.all;
18	    use work.definitions_pkg.all;
19	
20	------------------------------------------------------------------------------
21	-- Entity
22	------------------------------------------------------------------------------
23	entity axi_mm_reader_wrp is
24	    generic
25	    (
26	        -- Config Parameters
27	        ClkFrequencyHz      : natural   := 100_000_000;
28	        TimeoutUs_g         : natural   := 100;
29	        MaxRegCount_g       : natural   := 1024;
30	        MinBuffers_g        : natural   := 4;
31	        Output_g            : string    := "AXIMM"; -- AXIS for AXI Sream output, AXIMM for reading via register bank
32	        AxiSlaveAddrWidth_g : natural   := 14;
33	
34	        -- AXI Parameters
35	        C_S00_AXI_ID_WIDTH  : integer := 1                  -- Width of ID for for write address, write data, read address and read data
36	    );
37	    port
38	    (
39	        -----------------------------------------------------------------------------
40	        -- Control Signals
41	        -----------------------------------------------------------------------------
42	        Clk                         : in    std_logic;
43	        Rst                         : in    std_logic;
44	
45	        -----------------------------------------------------------------------------
46	        -- Events
47	        -----------------------------------------------------------------------------
48	        Trig                        : in    std_logic := '0';
49	        DoneIrq                     : out   std_logic;
50	
51	        -----------------------------------------------------------------------------
52	        -- Axi Slave Bus Interface
53	        -----------------------------------------------------------------------------
54	        -- Read address channel
55	        s00_axi_arid                : in    std_logic_vector(C_S00_AXI_ID_WIDTH-1   downto 0);
56	        s00_axi_araddr              : in    std_logic_vector(AxiSlaveAddrWidth_g-1 downto 0);
57	        s00_axi_arlen               : in    std_logic_vector(7 downto 0);
58	        s00_axi_arsize              : in    std_logic_vector(2 downto 0);
59	        s00_axi_arburst             : in    std_logic_vector(1 downto 0);
60	        s00_axi_arlock              : in    std_logic;
61	        s00_axi_arcache             : in    std_logic_vector(3 downto 0);
62	        s00_axi_arprot              : in    std_logic_vector(2 downto 0);
63	        s00_axi_arvalid             : in    std_logic;
64	        s00_axi_arready             : out   std_logic;
65	        -- Read data channel
66	        s00_axi_rid                 : out   std_logic_vector(C_S00_AXI_ID_WIDTH-1 downto 0);
67	        s00_axi_rdata               : out   std_logic_vector(31 downto 0);
68	        s00_axi_rresp               : out   std_logic_vector(1 downto 0);
69	        s00_axi_rlast               : out   std_logic;
70	        s00_axi_rvalid              : out   std_logic;
71	        s00_axi_rready              : in    std_logic;
72	        -- Write address channel
73	        s00_axi_awid                : in    std_logic_vector(C_S00_AXI_ID_WIDTH-1   downto 0);
74	        s00_axi_awaddr              : in    std_logic_vector(AxiSlaveAddrWidth_g-1 downto 0);
75	        s00_axi_awlen               : in    std_logic_vector(7 downto 0);
76	        s00_axi_awsize              : in    std_logic_vector(2 downto 0);
77	        s00_axi_awburst             : in    std_logic_vector(1 downto 0);
78	        s00_axi_awlock              : in    std_logic;
79	        s00_axi_awcache             : in    std_logic_vector(3 downto 0);
80	        s00_axi_awprot              : in    std_logic_vector(2 downto 0);
81	        s00_axi_awvalid             : in    std_logic;
82	        s00_axi_awready             : out   std_logic;
83	        -- Write data channel
84	        s00_axi_wdata               : in    std_logic_vector(31    downto 0);
85	        s00_axi_wstrb               : in    std_logic_vector(3 downto 0);
86	        s00_axi_wlast               : in    std_logic;
87	        s00_axi_wvalid              : in    std_logic;
88	        s00_axi_wready              : out   std_logic;
89	        -- Write response channel
90	        s00_axi_bid                 : out   std_logic_vector(C_S00_AXI_ID_WIDTH-1 downto 0);
91	        s00_axi_bresp               : out   std_logic_vector(1 downto 0);
92	        s00_axi_bvalid              : out   std_logic;
93	        s00_axi_bready              : in    std_logic;
94	
95	        -----------------------------------------------------------------------------
96	        -- Axi Master Bus Interface
97	        -----------------------------------------------------------------------------
98	        -- AXI Read Address Channel
99	        m00_axi_araddr              : out   std_logic_vector(31 downto 0);
100	        m00_axi_arlen               : out   std_logic_vector(7 downto 0);
101	        m00_axi_arsize              : out   std_logic_vector(2 downto 0);
102	        m00_axi_arburst             : out   std_logic_vector(1 downto 0);
103	        m00_axi_arlock              : out   std_logic;
104	        m00_axi_arcache             : out   std_logic_vector(3 downto 0);
105	        m00_axi_arprot              : out   std_logic_vector(2 downto 0);
106	        m00_axi_arvalid             : out   std_logic;
107	        m00_axi_arready             : in    std_logic;
108	        -- AXI Read Data Channel
109	        m00_axi_rdata               : in    std_logic_vector(31 downto 0);
110	        m00_axi_rresp               : in    std_logic_vector(1 downto 0);
111	        m00_axi_rlast               : in    std_logic;
112	        m00_axi_rvalid              : in    std_logic;
113	        m00_axi_rready              : out   std_logic;
114	
115	        -----------------------------------------------------------------------------
116	        -- Stream Output
117	        -----------------------------------------------------------------------------
118	        m_axis_tdata                : out   std_logic_vector(31 downto 0);
119	        m_axis_tvalid               : out   std_logic;
120	        m_axis_tready               : in    std_logic := '0';
121	        m_axis_tlast                : out   std_logic
122	    );
123	
124	end entity axi_mm_reader_wrp;
125	
126	------------------------------------------------------------------------------
127	-- Architecture section
128	------------------------------------------------------------------------------
129	
130	architecture rtl of axi_mm_reader_wrp is
131	
132	    -- Array of desired number of chip enables for each address range
133	    constant USER_SLV_NUM_REG               : integer              := 2**log2ceil(RegCount_c);
134	    constant TimeoutCkCycles_c              : natural               := integer(real(ClkFrequencyHz)*real(TimeoutUs_g)/1.0e6);
135	
136	    -- IP Interconnect (IPIC) signal declarations
137	    signal reg_rd                           : std_logic_vector(USER_SLV_NUM_REG-1 downto  0);
138	    signal reg_rdata                        : t_aslv32(0 to USER_SLV_NUM_REG-1) := (others => (others => '0'));
139	    signal reg_wr                           : std_logic_vector(USER_SLV_NUM_REG-1 downto  0);
140	    signal reg_wdata                        : t_aslv32(0 to USER_SLV_NUM_REG-1);
141	    signal mem_addr                         : std_logic_vector(AxiSlaveAddrWidth_g-1 downto 0);
142	    signal mem_wr                           : std_logic_vector( 3 downto 0);
143	    signal mem_wdata                        : std_logic_vector(31 downto 0);
144	    signal mem_rdata                        : std_logic_vector(31 downto 0);
145	    signal mem_wrena                        : std_logic;
146	
147	    -- Ohter Signals
148	    signal RstN                         : std_logic;
149	    signal AxiM_CmdRd_Addr              : std_logic_vector(31 downto 0);
150	    signal AxiM_CmdRd_Vld               : std_logic;
151	    signal AxiM_CmdRd_Rdy               : std_logic;
152	    signal AxiM_Rd_Done                 : std_logic;
153	    signal AxiM_RdDat_Data              : std_logic_vector(31 downto 0);
154	    signal AxiM_RdDat_Vld               : std_logic;
155	    signal AxiM_RdDat_Rdy               : std_logic;
156	    signal AxiS_Vld                     : std_logic;
157	    signal AxiS_Rdy                     : std_logic;
158	    signal AxiS_Last                    : std_logic;
159	    signal AxiS_Data                    : std_logic_vector(31 downto 0);
160	    signal AxiS_Level                   : std_logic_vector(31 downto 0);
161	
162	
163	begin
164	
165	    RstN <= not Rst;
166	
167	   -----------------------------------------------------------------------------
168	   -- Implement AXI-S Output if needed
169	   -----------------------------------------------------------------------------
170	   g_axis : if Output_g = "AXIS" generate
171	    m_axis_tdata    <= AxiS_Data;
172	    m_axis_tvalid   <= AxiS_Vld;
173	    AxiS_Rdy        <= m_axis_tready;
174	    m_axis_tlast    <= AxiS_Last;
175		reg_rdata(RegIdx_Level_c)       <= AxiS_Level;
176	   end generate;
177	
178	   g_naxis : if Output_g /= "AXIS" generate
179	        m_axis_tvalid                   <= '0';
180	        AxiS_Rdy                        <= reg_rd(RegIdx_RdData_c);
181	        reg_rdata(RegIdx_RdData_c)      <= AxiS_Data;
182	        reg_rdata(RegIdx_RdLast_c)(BitIdx_RdLast_c) <= AxiS_Last;
183			reg_rdata(RegIdx_Level_c)       <= AxiS_Level;
184	   end generate;
185	   
186	   
187	
188	   -----------------------------------------------------------------------------
189	   -- AXI decode instance
190	   -----------------------------------------------------------------------------
191	   axi_slave_reg_inst : entity work.psi_common_axi_slave_ipif
192	   generic map
193	   (
194	      -- Users parameters
195	      NumReg_g                             => USER_SLV_NUM_REG,
196	      UseMem_g                             => true,
197	      -- Parameters of Axi Slave Bus Interface
198	      AxiIdWidth_g                         => C_S00_AXI_ID_WIDTH,
199	      AxiAddrWidth_g                       => AxiSlaveAddrWidth_g
200	   )
201	   port map
202	   (
203	      --------------------------------------------------------------------------
204	      -- Axi Slave Bus Interface
205	      --------------------------------------------------------------------------
206	      -- System
207	      s_axi_aclk                  => Clk,
208	      s_axi_aresetn               => RstN,
209	      -- Read address channel
210	      s_axi_arid                  => s00_axi_arid,
211	      s_axi_araddr                => s00_axi_araddr,
212	      s_axi_arlen                 => s00_axi_arlen,
213	      s_axi_arsize                => s00_axi_arsize,
214	      s_axi_arburst               => s00_axi_arburst,
215	      s_axi_arlock                => s00_axi_arlock,
216	      s_axi_arcache               => s00_axi_arcache,
217	      s_axi_arprot                => s00_axi_arprot,
218	      s_axi_arvalid               => s00_axi_arvalid,
219	      s_axi_arready               => s00_axi_arready,
220	      -- Read data channel
221	      s_axi_rid                   => s00_axi_rid,
222	      s_axi_rdata                 => s00_axi_rdata,
223	      s_axi_rresp                 => s00_axi_rresp,
224	      s_axi_rlast                 => s00_axi_rlast,
225	      s_axi_rvalid                => s00_axi_rvalid,
226	      s_axi_rready                => s00_axi_rready,
227	      -- Write address channel
228	      s_axi_awid                  => s00_axi_awid,
229	      s_axi_awaddr                => s00_axi_awaddr,
230	      s_axi_awlen                 => s00_axi_awlen,
231	      s_axi_awsize                => s00_axi_awsize,
232	      s_axi_awburst               => s00_axi_awburst,
233	      s_axi_awlock                => s00_axi_awlock,
234	      s_axi_awcache               => s00_axi_awcache,
235	      s_axi_awprot                => s00_axi_awprot,
236	      s_axi_awvalid               => s00_axi_awvalid,
237	      s_axi_awready               => s00_axi_awready,
238	      -- Write data channel
239	      s_axi_wdata                 => s00_axi_wdata,
240	      s_axi_wstrb                 => s00_axi_wstrb,
241	      s_axi_wlast                 => s00_axi_wlast,
242	      s_axi_wvalid                => s00_axi_wvalid,
243	      s_axi_wready                => s00_axi_wready,
244	      -- Write response channel
245	      s_axi_bid                   => s00_axi_bid,
246	      s_axi_bresp                 => s00_axi_bresp,
247	      s_axi_bvalid                => s00_axi_bvalid,
248	      s_axi_bready                => s00_axi_bready,
249	      --------------------------------------------------------------------------
250	      -- Register Interface
251	      --------------------------------------------------------------------------
252	      o_reg_rd                    => reg_rd,
253	      i_reg_rdata                 => reg_rdata,
254	      o_reg_wr                    => reg_wr,
255	      o_reg_wdata                 => reg_wdata,
256	      --------------------------------------------------------------------------
257	      -- Memory Interface
258	      --------------------------------------------------------------------------
259	      o_mem_addr                  => mem_addr,
260	      o_mem_wr                    => mem_wr,
261	      o_mem_wdata                 => mem_wdata,
262	      i_mem_rdata                 => mem_rdata
263	   );
264	   mem_wrena <= '1' when mem_wr /= "0000" else '0';
265	
266	
267	
268	    -----------------------------------------------------------------------------
269	    -- AXI Master Interface
270	    -----------------------------------------------------------------------------
271	    i_axim : entity work.psi_common_axi_master_simple
272	        generic map (
273	            AxiAddrWidth_g              => 32,
274	            AxiDataWidth_g              => 32,
275	            AxiMaxBeats_g               => 1,
276	            AxiMaxOpenTrasactions_g     => 4,
277	            UserTransactionSizeBits_g   => 1,
278	            DataFifoDepth_g             => 16,
279	            ImplRead_g                  => true,
280	            ImplWrite_g                 => false,
281	            RamBehavior_g               => "RBW"
282	        )
283	        port map (
284	            M_Axi_Aclk      => Clk,
285	            M_Axi_Aresetn   => RstN,
286	            CmdRd_Addr      => AxiM_CmdRd_Addr,
287	            CmdRd_Size      => "1",
288	            CmdRd_LowLat    => '0',
289	            CmdRd_Vld       => AxiM_CmdRd_Vld,
290	            CmdRd_Rdy       => AxiM_CmdRd_Rdy,
291	            RdDat_Data      => AxiM_RdDat_Data,
292	            RdDat_Vld       => AxiM_RdDat_Vld,
293	            RdDat_Rdy       => AxiM_RdDat_Rdy,
294	            M_Axi_ArAddr    => m00_axi_araddr,
295	            M_Axi_ArLen     => m00_axi_arlen,
296	            M_Axi_ArSize    => m00_axi_arsize,
297	            M_Axi_ArBurst   => m00_axi_arburst,
298	            M_Axi_ArLock    => m00_axi_arlock,
299	            M_Axi_ArCache   => m00_axi_arcache,
300	            M_Axi_ArProt    => m00_axi_arprot,
301	            M_Axi_ArValid   => m00_axi_arvalid,
302	            M_Axi_ArReady   => m00_axi_arready,
303	            M_Axi_RData     => m00_axi_rdata,
304	            M_Axi_RResp     => m00_axi_rresp,
305	            M_Axi_RLast     => m00_axi_rlast,
306	            M_Axi_RValid    => m00_axi_rvalid,
307	            M_Axi_RReady    => m00_axi_rready
308	        );
309	
310	    -----------------------------------------------------------------------------
311	    -- Implementation
312	    -----------------------------------------------------------------------------
313	    i_impl : entity work.axi_mm_reader
314	        generic map (
315	            TimeoutCkCycles_g   => TimeoutCkCycles_c,
316	            MaxRegCount_g       => MaxRegCount_g,
317	            MinBuffers_g        => MinBuffers_g,
318	            AxiAddrWidth_g      => 32,
319	            RamBehavior_g       => "RBW"
320	        )
321	        port map (
322	            Clk             => Clk,
323	            Rst             => Rst,
324	            Trig            => Trig,
325	            DoneIrq         => DoneIrq,
326	            RegCount        => reg_wdata(RegIdx_RegCnt_c)(log2ceil(MaxRegCount_g)-1 downto 0),
327	            Enable          => reg_wdata(RegIdx_Ctrl_c)(BitIdx_Ctrl_Ena_c),
328	            RegCfg_Idx      => mem_addr(log2ceil(MaxRegCount_g)+1 downto 2),
329	            RegCfg_WrReg    => mem_wdata,
330	            RegCfg_RdReg    => mem_rdata,
331	            RegCfg_Wr       => mem_wrena,
332	            AxiM_CmdRd_Addr => AxiM_CmdRd_Addr,
333	            AxiM_CmdRd_Vld  => AxiM_CmdRd_Vld,
334	            AxiM_CmdRd_Rdy  => AxiM_CmdRd_Rdy,
335	            AxiM_RdDat_Data => AxiM_RdDat_Data,
336	            AxiM_RdDat_Vld  => AxiM_RdDat_Vld,
337	            AxiM_RdDat_Rdy  => AxiM_RdDat_Rdy,
338	            AxiS_Vld        => AxiS_Vld,
339	            AxiS_Rdy        => AxiS_Rdy,
340	            AxiS_Last       => AxiS_Last,
341	            AxiS_Data       => AxiS_Data,
342	            AxiS_Level      => AxiS_Level
343	        );
344	
345	
346	
347	end rtl;
348

